let siteData = null;
function getPrefix(){ return location.pathname.includes('/stores/') ? '../' : ''; }
async function loadData(){
  if(siteData) return siteData;
  const prefix = getPrefix();
  try{
    const res = await fetch(prefix + 'data.json', {cache:'no-store'});
    if(!res.ok) throw new Error('data load failed');
    siteData = await res.json();
  }catch(err){
    siteData = FALLBACK_DATA;
  }
  return siteData;
}
